interface SMSArgs {
  phone: string;
  message: string;
  key: string;
}

interface SMSResult {
  success: boolean;
  error?: string;
  quotaRemaining?: number;
  textId?: string;
}

export const handler = async (event: { arguments: SMSArgs }): Promise<SMSResult> => {
  const { phone, message, key } = event.arguments;

  if (!phone || !message || !key) {
    return {
      success: false,
      error: 'Missing required fields: phone, message, key',
    };
  }

  try {
    const response = await fetch('https://textbelt.com/text', {
      method: 'POST',
      headers: {
        'Content-Type': 'application/json',
      },
      body: JSON.stringify({ phone, message, key }),
    });

    const result = await response.json() as any;

    console.log('TextBelt full response:', JSON.stringify(result));
    console.log('Phone:', phone, 'Key prefix:', key.substring(0, 8) + '...');

    return {
      success: result.success,
      error: result.error,
      quotaRemaining: result.quotaRemaining,
      textId: result.textId,
    };
  } catch (error) {
    console.error('SMS API error:', error);
    return {
      success: false,
      error: error instanceof Error ? error.message : 'SMS service unavailable',
    };
  }
};
